import json
import boto3
import logging
from urllib.parse import unquote_plus

# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

def lambda_handler(event, context):
    # Log the received event
    logger.info(f"Received event: {json.dumps(event, indent=2)}")
    
    for record in event['Records']:
        bucket = record['s3']['bucket']['name']
        key = unquote_plus(record['s3']['object']['key'])
        
        try:
            # Read object from S3
            logger.info(f"Reading S3 object from bucket: {bucket}, key: {key}")
            response = s3_client.get_object(Bucket=bucket, Key=key)
            content = response['Body'].read()
            
            # Process the content (placeholder for actual image processing)
            processed_content = content[::-1]  # For demonstration, reverse content
            
            # Write back processed image to S3
            output_bucket = 'processed-images-bucket-name'  # Change as needed
            output_key = f"processed/{key}"
            logger.info(f"Writing processed image to bucket: {output_bucket}, key: {output_key}")
            s3_client.put_object(Bucket=output_bucket, Key=output_key, Body=processed_content)
            
            # Send notification via SNS
            topic_arn = 'arn:aws:sns:us-east-1:123456789012:ImageProcessingTopic'  # Change as needed
            sns_message = f"Processed image {key} from bucket {bucket} and saved to {output_key}"
            logger.info(f"Sending SNS notification: {sns_message}")
            sns_client.publish(TopicArn=topic_arn, Message=sns_message, Subject='Image Processed')
            
        except Exception as e:
            logger.error(f"Error processing record: {e}")
            raise

